input.command:
WS=skills/document-harness-workspace/20260715-pr14-drift-fix
mkdir -p "$WS/logs"

# eval1: harness-init-distill (fixture-a)
cp -R eval-fixtures/document-harness/fixture-a-init "$WS/eval1-init"
# eval2: harness-sync-redistill (fixture-b)
cp -R eval-fixtures/document-harness/fixture-b-sync "$WS/eval2-sync"
# eval3: audit-distill-and-verify (fixture-c)
cp -R eval-fixtures/document-harness/fixture-c-audit "$WS/eval3-audit"
# eval4: audit-memory-canonicality (fixture-d)
cp -R eval-fixtures/document-harness/fixture-d-memory-audit "$WS/eval4-memory"

# ブランチ状態のスキルを各 iteration に配置（placement-guide 変更込みの model を含む）
for d in eval1-init eval2-sync eval3-audit eval4-memory; do
  mkdir -p "$WS/$d/.claude/skills"
  cp -R skills/1natsu-document-harness "$WS/$d/.claude/skills/"
  cp -R skills/1natsu-document-harness-audit "$WS/$d/.claude/skills/"
  cp -R skills/1natsu-document-harness-model "$WS/$d/.claude/skills/"
done

# プロンプトをファイル化（evals.json から抽出）
node -e '
const fs = require("fs");
const ws = process.argv[1];
const h = JSON.parse(fs.readFileSync("skills/1natsu-document-harness/evals/evals.json","utf8"));
const a = JSON.parse(fs.readFileSync("skills/1natsu-document-harness-audit/evals/evals.json","utf8"));
fs.writeFileSync(ws+"/eval1-init/prompt.txt", h.evals[0].prompt);
fs.writeFileSync(ws+"/eval2-sync/prompt.txt", h.evals[1].prompt);
fs.writeFileSync(ws+"/eval3-audit/prompt.txt", a.evals[0].prompt);
const abs = require("path").resolve(ws+"/eval4-memory");
fs.writeFileSync(ws+"/eval4-memory/prompt.txt", a.evals[1].prompt.replaceAll("<fixture>", abs));
' "$WS"
ls "$WS"; echo ---; cat "$WS/eval4-memory/prompt.txt"
